import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.CsxL8ROK.js";const u=JSON.parse('{"title":"Commands","description":"","frontmatter":{},"headers":[],"relativePath":"commands.md","filePath":"commands.md"}'),i={name:"commands.md"};function r(n,e,d,c,l,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h1><h2 id="codex-review" tabindex="-1"><code>/codex-review</code> <a class="header-anchor" href="#codex-review" aria-label="Permalink to &quot;`/codex-review`&quot;">​</a></h2><p>Posts an AI code review as a GitHub Pull Request review on the current PR.</p><h3 id="basic-usage" tabindex="-1">Basic usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic usage&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex-review</span></span></code></pre></div><h3 id="with-extra-instructions" tabindex="-1">With extra instructions <a class="header-anchor" href="#with-extra-instructions" aria-label="Permalink to &quot;With extra instructions&quot;">​</a></h3><p>Any text after the command is passed to the model as additional context:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex-review focus on security and authentication edge cases</span></span>\n<span class="line"><span>/codex-review this is a hotfix — check for regressions only</span></span>\n<span class="line"><span>/codex-review be extra strict about missing tests</span></span></code></pre></div><h3 id="force-re-review" tabindex="-1">Force re-review <a class="header-anchor" href="#force-re-review" aria-label="Permalink to &quot;Force re-review&quot;">​</a></h3><p>By default the bot skips PRs it has already reviewed at the same commit SHA. Use <code>--force</code> to override:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex-review --force</span></span></code></pre></div><p>Flags and extra instructions can be combined in any order:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex-review --force check for dependency injection issues</span></span></code></pre></div><h2 id="trust-model" tabindex="-1">Trust model <a class="header-anchor" href="#trust-model" aria-label="Permalink to &quot;Trust model&quot;">​</a></h2><p>The bot only responds to comments from users with these GitHub author associations:</p><table tabindex="0"><thead><tr><th>Association</th><th>Who</th></tr></thead><tbody><tr><td><code>OWNER</code></td><td>The repository owner</td></tr><tr><td><code>MEMBER</code></td><td>A member of the organization that owns the repo</td></tr><tr><td><code>COLLABORATOR</code></td><td>Someone explicitly added as a collaborator</td></tr></tbody></table><p>Comments from other users (e.g. external contributors, bots) are silently ignored.</p><h2 id="automatic-reviews" tabindex="-1">Automatic reviews <a class="header-anchor" href="#automatic-reviews" aria-label="Permalink to &quot;Automatic reviews&quot;">​</a></h2><p>If <code>REVIEW_ENABLED=true</code>, the bot also triggers automatically on:</p><ul><li><code>pull_request.opened</code></li><li><code>pull_request.reopened</code></li><li><code>pull_request.synchronize</code> (new commits pushed)</li></ul><p>Draft PRs are skipped automatically.</p><h2 id="deduplication" tabindex="-1">Deduplication <a class="header-anchor" href="#deduplication" aria-label="Permalink to &quot;Deduplication&quot;">​</a></h2><p>The bot embeds a <code>Reviewed commit: &lt;sha&gt;</code> marker in every review body. Before submitting a new review, it fetches existing reviews and skips if the same SHA has already been reviewed. Use <code>--force</code> to bypass this check.</p>',23)])])}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
